import React, { useState } from 'react';
import { useFavorites } from '../context/FavoritesContext';
import './RecipeCard.css';

const FALLBACK = 'https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&w=600&h=400&q=80';

export default function RecipeCard({ recipe, variant = 'grid', style }) {
  const { isFavorite, toggleFavorite } = useFavorites();
  const [imgErr, setImgErr] = useState(false);
  const [pop, setPop] = useState(false);
  const faved = isFavorite(recipe.id ?? recipe.recipeId);

  const cuisine = recipe.cuisines?.[0] || '';
  const dishType = recipe.dishTypes?.[0] || '';
  const tag = [cuisine, dishType].filter(Boolean).map(s => s.charAt(0).toUpperCase() + s.slice(1)).join(' · ');

  const onHeart = async (e) => {
    e.preventDefault(); e.stopPropagation();
    setPop(true); setTimeout(() => setPop(false), 400);
    await toggleFavorite({ ...recipe, id: recipe.id ?? recipe.recipeId });
  };

  if (variant === 'featured') {
    return (
      <div className="rcard rcard--featured" style={style}>
        <div className="rcard__img-wrap">
          <img src={imgErr ? FALLBACK : (recipe.image || FALLBACK)} alt={recipe.title} onError={() => setImgErr(true)} loading="lazy" />
          <button className={`rcard__heart${faved?' active':''}${pop?' pop':''}`} onClick={onHeart} aria-label="Toggle favorite">
            <i className={faved ? 'fas fa-heart' : 'far fa-heart'} />
          </button>
        </div>
        <div className="rcard__body">
          {tag && <p className="rcard__tag eyebrow">{tag}</p>}
          <h3 className="rcard__title rcard__title--lg">{recipe.title}</h3>
          <div className="rcard__meta">
            {recipe.readyInMinutes && <span><i className="fas fa-clock"/> {recipe.readyInMinutes} min</span>}
            {recipe.servings && <span><i className="fas fa-users"/> {recipe.servings} servings</span>}
          </div>
          <a href={recipe.sourceUrl || '#'} target="_blank" rel="noopener noreferrer" className="rcard__link">
            View recipe <i className="fas fa-arrow-right"/>
          </a>
        </div>
      </div>
    );
  }

  return (
    <div className="rcard" style={style}>
      <div className="rcard__img-wrap">
        <img src={imgErr ? FALLBACK : (recipe.image || FALLBACK)} alt={recipe.title} onError={() => setImgErr(true)} loading="lazy" />
        <button className={`rcard__heart${faved?' active':''}${pop?' pop':''}`} onClick={onHeart} aria-label="Toggle favorite">
          <i className={faved ? 'fas fa-heart' : 'far fa-heart'} />
        </button>
      </div>
      <div className="rcard__body">
        {tag && <p className="rcard__tag eyebrow">{tag}</p>}
        <h3 className="rcard__title">{recipe.title}</h3>
        <div className="rcard__meta">
          {recipe.readyInMinutes && <span><i className="fas fa-clock"/> {recipe.readyInMinutes} min</span>}
          {recipe.servings && <span><i className="fas fa-users"/> {recipe.servings}</span>}
        </div>
        <a href={recipe.sourceUrl || '#'} target="_blank" rel="noopener noreferrer" className="rcard__link">
          View recipe <i className="fas fa-arrow-right"/>
        </a>
      </div>
    </div>
  );
}
